const express = require('express');

const app = express();
const port = process.env.PORT || 3000;

function timestamp() {
  return new Date().toISOString();
}

function normalizeAction(value) {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) return String(value[0] ?? '');
  return String(value);
}

app.get('/log', (req, res) => {
  const action = normalizeAction(req.query.action).trim();

  if (!action) {
    return res.status(400).json({ ok: false, error: 'Missing required query parameter: action' });
  }

  console.log(`[${timestamp()}] ACTION: ${action}`);

  res.json({ ok: true, timestamp: timestamp(), action });
});

app.get('/', (_req, res) => {
  res.type('text').send('Audit logger running. Use GET /log?action=...');
});

app.listen(port, () => {
  console.log(`[${timestamp()}] Server started on port ${port}`);
});